export const IsEmptyObj = (input: object): boolean => {
  if (typeof input !== 'object' || input === null) return true;
  if (Object.keys(input).length > 0) return false;
  return true;
}

export const ExtractCorrelationId = (source: any): string | undefined => {
  // The API exposes the correlation id only via the X-Correlation-Id response header.
  // Accept either an axios error or an axios response.
  const response = source?.response ?? source;
  const headers = response?.headers;
  if (!headers) return undefined;
  return (
    headers['x-correlation-id'] ||
    headers['X-Correlation-Id'] ||
    (typeof headers.get === 'function' ? headers.get('x-correlation-id') : undefined) ||
    undefined
  );
}

export const ISODateTimeToReadable = (isoString: string): string => {
  const options: Intl.DateTimeFormatOptions = {
    year: 'numeric',
    month: 'short',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  };

  const date = new Date(isoString);
  const formattedDate = new Intl.DateTimeFormat('en-US', options).format(date);
  const timeIndex = formattedDate.indexOf(',') + 2;
  const finalFormattedDate =
    `${formattedDate.substring(0, timeIndex)} ${formattedDate.substring(timeIndex).toLowerCase()}`;

  return finalFormattedDate;
};

export const UnixDateTimeToReadable = (unixTimestamp: number): string => {
  // Backend sends timestamp in milliseconds, not seconds
  const date = new Date(unixTimestamp);
  return ISODateTimeToReadable(date.toISOString());
}

export const DateTimeToUnix = (datetime: Date): number => {
  return Math.floor(datetime.getTime() / 1000);
}

export const DateTimeIsoToUnix = (datetime: string): number => {
  return DateTimeToUnix(new Date(datetime));
}

export const DateTimeReadable = (datetime: Date): string => {
  const options: Intl.DateTimeFormatOptions = {
    year: 'numeric',
    month: 'short',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: true,
  };

  const formattedDate = new Intl.DateTimeFormat('en-US', options).format(datetime);
  const timeIndex = formattedDate.indexOf(',') + 2;
  const finalFormattedDate =
    `${formattedDate.substring(0, timeIndex)} ${formattedDate.substring(timeIndex).toLowerCase()}`;

  return finalFormattedDate;
}

export const DateTimeReadableWithTimezone = (datetime: Date): string => {
  return DateTimeReadable(datetime);
}

export const UnixTimestampToReadableWithTimezone = (timestamp: number): string => {
  return DateTimeReadableWithTimezone(new Date(timestamp));
}

export const UnixTimestampToDateTimeInput = (timestamp: number): string => {
  // Convert Unix timestamp to datetime-local input format (YYYY-MM-DDTHH:MM)
  // Converts UTC timestamp to local time for display in input field
  const date = new Date(timestamp);
  
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  const hours = String(date.getHours()).padStart(2, '0');
  const minutes = String(date.getMinutes()).padStart(2, '0');
  
  return `${year}-${month}-${day}T${hours}:${minutes}`;
}

// Method to check if two json objects have same properties and values
export const AreObjectsEqual = (obj1: Record<string, unknown>, obj2: Record<string, unknown>): boolean => {
  if (typeof obj1 !== 'object' || typeof obj2 !== 'object' || obj1 === null || obj2 === null) return false;
  if (Object.keys(obj1).length !== Object.keys(obj2).length) return false;

  for (const key in obj1) {
    if (obj1.hasOwnProperty(key) && obj2.hasOwnProperty(key)) {
      if (obj1[key] !== obj2[key]) return false;
    }
  }

  return true;
}